#include <bits/stdc++.h>
using namespace std;

const int N=110,mod=1e9+7;

int T,n,m,k,x[N],y[N],f[N],g[N],t[N];
char s[N*31];

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int main(){
    scanf("%d",&T);
    if(T==1){
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
            scanf("%d%d",&x[i],&y[i]);
        memset(f,0,sizeof(f));
        for(int i=1;i<=n;i++){
            memset(g,0,sizeof(g));
            int num=y[i];
            g[0]=1;
            for(int j=1;j<=n;j++)
                if(i!=j){
                    num=1ll*num*qpow(x[i]-x[j],mod-2)%mod;
                    t[0]=1ll*g[0]*(-x[j])%mod;
                    for(int k=1;k<n;k++)
                        t[k]=(g[k-1]+1ll*g[k]*(-x[j]))%mod;
                    for(int k=0;k<n;k++)
                        g[k]=t[k];
                }
            for(int j=0;j<n;j++)
                f[j]=(f[j]+1ll*g[j]*num)%mod;
        }
        printf("%d\n",n*30);
        for(int i=0;i<n;i++){
            f[i]=(f[i]+mod)%mod;
            for(int j=0;j<30;j++)
                printf("%d",(f[i]>>j)&1);
        }
        puts("");
        /*
        for(int i=0;i<n;i++)
            printf("%d ",f[i]);
        puts("");
        for(int i=1;i<=n;i++){
            int sum=0;
            for(int j=0,p=1;j<n;j++,p=1ll*p*x[i]%mod)
                sum=(sum+1ll*f[j]*p)%mod;
            printf("%d\n",sum);
        }
        */
    }else{
        scanf("%d%d%d",&n,&m,&k);
        scanf("%s",s);
        for(int i=0;i<n;i++){
            for(int j=0;j<30;j++)
                f[i]+=(1ll<<j)*(s[i*30+j]-'0');
            //printf("%d\n",f[i]);
        }
        while(m--){
            int x,y=0;
            scanf("%d",&x);
            for(int i=0,p=1;i<n;i++,p=1ll*p*x%mod)
                y=(y+1ll*f[i]*p)%mod;
            printf("%d\n",y);
        }
    }
    return 0;
}
